PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE IF NOT EXISTS "migrations" ("id" integer primary key autoincrement not null, "migration" varchar not null, "batch" integer not null);
CREATE TABLE IF NOT EXISTS "users" ("id" integer primary key autoincrement not null, "name" varchar not null, "email" varchar not null, "email_verified_at" datetime, "password" varchar not null, "remember_token" varchar, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "password_reset_tokens" ("email" varchar not null, "token" varchar not null, "created_at" datetime, primary key ("email"));
CREATE TABLE IF NOT EXISTS "sessions" ("id" varchar not null, "user_id" integer, "ip_address" varchar, "user_agent" text, "payload" text not null, "last_activity" integer not null, primary key ("id"));
CREATE TABLE IF NOT EXISTS "cache" ("key" varchar not null, "value" text not null, "expiration" integer not null, primary key ("key"));
CREATE TABLE IF NOT EXISTS "cache_locks" ("key" varchar not null, "owner" varchar not null, "expiration" integer not null, primary key ("key"));
CREATE TABLE IF NOT EXISTS "jobs" ("id" integer primary key autoincrement not null, "queue" varchar not null, "payload" text not null, "attempts" integer not null, "reserved_at" integer, "available_at" integer not null, "created_at" integer not null);
CREATE TABLE IF NOT EXISTS "job_batches" ("id" varchar not null, "name" varchar not null, "total_jobs" integer not null, "pending_jobs" integer not null, "failed_jobs" integer not null, "failed_job_ids" text not null, "options" text, "cancelled_at" integer, "created_at" integer not null, "finished_at" integer, primary key ("id"));
CREATE TABLE IF NOT EXISTS "failed_jobs" ("id" integer primary key autoincrement not null, "uuid" varchar not null, "connection" text not null, "queue" text not null, "payload" text not null, "exception" text not null, "failed_at" datetime not null default CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS "notifications_templates" ("id" integer primary key autoincrement not null, "name" varchar not null, "key" varchar not null, "title" varchar not null, "body" text, "url" varchar, "icon" varchar default 'heroicon-o-check-circle', "type" varchar default 'success', "providers" text, "action" varchar default 'manual', "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "user_notifications" ("id" integer primary key autoincrement not null, "model_type" varchar, "model_id" integer, "template_id" integer, "title" text not null, "description" text, "url" varchar, "icon" varchar default 'heroicon-o-check-circle', "type" varchar default 'success', "privacy" varchar default 'public', "data" text, "created_by" integer not null, "created_at" datetime, "updated_at" datetime, foreign key("template_id") references "notifications_templates"("id") on delete cascade, foreign key("created_by") references "users"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "user_has_notifications" ("id" integer primary key autoincrement not null, "model_type" varchar not null, "model_id" integer not null, "provider" varchar default 'pusher', "provider_token" varchar, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "user_read_notifications" ("id" integer primary key autoincrement not null, "model_type" varchar not null, "model_id" integer not null, "notification_id" integer not null, "read" tinyint(1) not null default '0', "open" tinyint(1) not null default '0', "created_at" datetime, "updated_at" datetime, foreign key("notification_id") references "user_notifications"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "template_has_roles" ("template_id" integer not null, "role_id" integer not null);
CREATE TABLE IF NOT EXISTS "notifications_logs" ("id" integer primary key autoincrement not null, "model_type" varchar, "model_id" integer, "title" text not null, "description" text, "type" varchar not null default 'info', "provider" varchar not null default 'fcm-api', "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "settings" ("id" integer primary key autoincrement not null, "group" varchar not null, "name" varchar not null, "locked" tinyint(1) not null default '0', "payload" text not null, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "teams" ("id" integer primary key autoincrement not null, "name" varchar, "portal_name" varchar, "industry" varchar, "business_location" varchar, "street_1" varchar, "street_2" varchar, "city" varchar, "province" varchar, "phone" varchar, "fax" varchar, "website" varchar, "inventory_start" date, "fiscal_year" varchar, "language" varchar, "created_at" datetime, "updated_at" datetime, "has_warehouses" tinyint(1) not null default '1', "logo" varchar not null, "currency_code" varchar not null default 'USD', "currency_symbol" varchar not null default '$', "email" varchar);
CREATE TABLE IF NOT EXISTS "team_user" ("id" integer primary key autoincrement not null, "user_id" integer not null, "team_id" integer not null, "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete cascade, foreign key("team_id") references "teams"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "sales_accounts" ("id" integer primary key autoincrement not null, "name" varchar not null, "created_at" datetime, "updated_at" datetime, "team_id" integer not null default '1');
CREATE TABLE IF NOT EXISTS "purchases_accounts" ("id" integer primary key autoincrement not null, "name" varchar not null, "created_at" datetime, "updated_at" datetime, "team_id" integer not null);
CREATE TABLE IF NOT EXISTS "manufucturers" ("id" integer primary key autoincrement not null, "name" varchar not null, "created_at" datetime, "updated_at" datetime, "team_id" integer not null default '1');
CREATE TABLE IF NOT EXISTS "brands" ("id" integer primary key autoincrement not null, "name" varchar not null, "created_at" datetime, "updated_at" datetime, "team_id" integer not null default '1');
CREATE TABLE IF NOT EXISTS "vendors" ("id" integer primary key autoincrement not null, "salutation" varchar, "first_name" varchar, "last_name" varchar, "company_name" varchar, "vendor_display_name" varchar, "email" varchar, "phone" varchar, "payment_terms" varchar, "created_at" datetime, "updated_at" datetime, "team_id" integer not null);
CREATE TABLE IF NOT EXISTS "item" ("id" integer primary key autoincrement not null, "item_type" varchar not null, "image" varchar, "name" varchar not null, "sku" varchar, "unit" varchar, "returnable_item" tinyint(1), "selling_price" integer not null, "sales_account_id" integer, "sales_description" varchar, "cost_price" integer not null, "purchase_account_id" integer, "purchases_description" varchar, "track_inventory_for_this_item" tinyint(1) not null default '0', "inventory_account" varchar, "opening_stock" integer, "opening_stock_rate_per_unit" integer, "reorder_level" integer, "preferred_vendor_id" integer, "dimensions" varchar, "weight" integer, "manufucturer_id" integer, "brand_id" integer, "upc" varchar, "mpn" varchar, "ean" varchar, "isbn" varchar, "team_id" integer not null, "created_at" datetime, "updated_at" datetime, "stock_on_hand" integer not null default '0', "committed_stock" integer not null default '0', "available_for_sale" integer not null default '0', "warehouse_id" integer, "part_number" varchar, "description" varchar, "condition" varchar, foreign key("team_id") references "teams"("id") on delete cascade, foreign key("sales_account_id") references "sales_accounts"("id") on delete cascade, foreign key("purchase_account_id") references "purchases_accounts"("id") on delete cascade, foreign key("preferred_vendor_id") references "vendors"("id") on delete cascade, foreign key("manufucturer_id") references "manufucturers"("id") on delete cascade, foreign key("brand_id") references "brands"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "payment_terms" ("id" integer primary key autoincrement not null, "name" varchar not null, "account_type" varchar, "bank" varchar, "account_name" varchar, "account_number" varchar, "branch" varchar, "swift_code" varchar, "branch_number" varchar, "created_at" datetime, "updated_at" datetime, "team_id" integer not null default '1');
CREATE TABLE IF NOT EXISTS "delivery_methods" ("id" integer primary key autoincrement not null, "name" varchar not null, "created_at" datetime, "updated_at" datetime, "team_id" integer not null);
CREATE TABLE IF NOT EXISTS "sales_persons" ("id" integer primary key autoincrement not null, "name" varchar not null, "email" varchar not null, "created_at" datetime, "updated_at" datetime, "team_id" integer not null default '1');
CREATE TABLE IF NOT EXISTS "model_has_permissions" ("permission_id" integer not null, "model_type" varchar not null, "model_id" integer not null, "team_id" integer not null, foreign key("permission_id") references "permissions"("id") on delete cascade, primary key ("team_id", "permission_id", "model_id", "model_type"));
CREATE TABLE IF NOT EXISTS "model_has_roles" ("role_id" integer not null, "model_type" varchar not null, "model_id" integer not null, "team_id" integer not null, foreign key("role_id") references "roles"("id") on delete cascade, primary key ("team_id", "role_id", "model_id", "model_type"));
CREATE TABLE IF NOT EXISTS "role_has_permissions" ("permission_id" integer not null, "role_id" integer not null, foreign key("permission_id") references "permissions"("id") on delete cascade, foreign key("role_id") references "roles"("id") on delete cascade, primary key ("permission_id", "role_id"));
CREATE TABLE IF NOT EXISTS "roles" ("id" integer primary key autoincrement not null, "team_id" integer, "name" varchar not null, "guard_name" varchar not null default 'web', "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "permissions" ("id" integer primary key autoincrement not null, "name" varchar not null, "guard_name" varchar not null default 'web', "created_at" datetime, "updated_at" datetime, "team_id" integer not null);
CREATE TABLE IF NOT EXISTS "expenses" ("id" integer primary key autoincrement not null, "date" date not null, "category_name" varchar not null, "amount" double not null, "vendor" varchar not null, "reference_number" varchar not null, "notes" varchar not null, "customer_name" varchar not null, "items" text not null, "created_at" datetime, "updated_at" datetime, "team_id" integer not null);
CREATE TABLE IF NOT EXISTS "payments_mades" ("id" integer primary key autoincrement not null, "payment_number" varchar not null, "payment_date" date not null, "payment_made" double not null, "payment_mode" varchar not null, "paid_through" varchar not null, "clear_applied_amount" tinyint(1) not null default '0', "reference_number" varchar not null, "notes" varchar not null, "items" text not null, "vendor_id" integer not null, "created_at" datetime, "updated_at" datetime, "team_id" integer not null, foreign key("vendor_id") references "vendors"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "item_groups" ("id" integer primary key autoincrement not null, "type" varchar not null, "item_group_name" varchar not null, "description" varchar, "returnable_item" tinyint(1) not null, "images" text not null, "unit" varchar not null, "attributes" text, "sales_account_id" integer not null, "purchases_account_id" integer not null, "inventory_account" varchar not null, "created_at" datetime, "updated_at" datetime, "team_id" integer not null, "warehouse_id" integer not null default '1', foreign key("sales_account_id") references "sales_accounts"("id") on delete cascade, foreign key("purchases_account_id") references "purchases_accounts"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "item_group_item" ("id" integer primary key autoincrement not null, "item_id" integer not null, "item_group_id" integer not null, "created_at" datetime, "updated_at" datetime, foreign key("item_id") references "item"("id") on delete cascade, foreign key("item_group_id") references "item_groups"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "bills" ("id" integer primary key autoincrement not null, "bill_number" varchar not null, "order_number" varchar not null, "bill_date" date not null, "due_date" date not null, "payment_terms" varchar not null, "subject" varchar, "discount" double, "notes" varchar, "items" text not null, "adjustment" double not null default '0', "sub_total" double not null default '0', "discount_account" varchar, "total" double not null default '0', "balance_due" double not null default '0', "received" tinyint(1) not null default '0', "payment_recorded" tinyint(1) not null default '0', "is_void" tinyint(1) not null default '0', "has_vendor_credits" tinyint(1) not null default '0', "vendor_id" integer not null, "team_id" integer not null, "created_at" datetime, "updated_at" datetime, "status" varchar not null default 'open', "applied_credits" text, foreign key("vendor_id") references "vendors"("id") on delete cascade, foreign key("team_id") references "teams"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "sales_receipts" ("id" integer primary key autoincrement not null, "sales_receipt_number" varchar not null, "items" text not null, "customer_notes" varchar, "terms_and_conditions" text, "payment_mode" varchar not null, "deposited_to" varchar not null, "reference_number" varchar not null, "sales_person_id" integer, "customer_id" integer not null, "team_id" integer not null, "created_at" datetime, "updated_at" datetime, "receipt_date" date not null, "sub_total" double not null, "discount" double not null default '0', "shipping_charges" double not null default '0', "adjustment" double not null default '0', "total" double not null, "payment_term_id" integer, foreign key("sales_person_id") references "sales_persons"("id") on delete cascade, foreign key("customer_id") references "customers"("id") on delete cascade, foreign key("team_id") references "teams"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "credit_notes" ("id" integer primary key autoincrement not null, "credit_note_number" varchar not null, "reference_number" varchar not null, "credit_note_date" date not null, "sales_person_id" integer, "subject" varchar, "items" text not null, "discount" double not null default '0', "adjustment" double not null default '0', "total" double not null, "amount_due" double not null, "sub_total" double not null, "notes" varchar, "is_draft" tinyint(1) not null default '0', "customer_id" integer not null, "team_id" integer not null, "created_at" datetime, "updated_at" datetime, foreign key("sales_person_id") references "sales_persons"("id") on delete cascade, foreign key("customer_id") references "customers"("id") on delete cascade, foreign key("team_id") references "teams"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "vendor_credits" ("id" integer primary key autoincrement not null, "credit_note_number" varchar not null, "order_number" varchar not null, "vendor_credit_date" date not null, "subject" varchar, "discount" double not null default '0', "adjustment" double not null default '0', "total" double not null, "amount_due" double not null, "sub_total" double not null, "notes" varchar, "items" text not null, "is_draft" tinyint(1) not null default '0', "created_at" datetime, "updated_at" datetime, "vendor_id" integer not null, "team_id" integer not null, foreign key("vendor_id") references "vendors"("id") on delete cascade, foreign key("team_id") references "teams"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "invoices" ("id" integer primary key autoincrement not null, "customer_id" integer not null, "invoice_number" varchar not null, "order_number" integer not null, "invoice_date" date not null, "payment_terms_id" integer not null, "due_date" date not null, "sales_person_id" integer, "subject" varchar, "customer_notes" varchar, "terms_and_conditions" text, "team_id" integer not null, "created_at" datetime, "updated_at" datetime, "items" text not null, "sub_total" double not null default '0', "discount" double not null default '0', "adjustment" double not null default '0', "total" double not null default '0', "balance_due" double not null default '0', "status" varchar not null default 'open', foreign key("sales_person_id") references "sales_persons"("id") on delete cascade on update no action, foreign key("payment_terms_id") references "payment_terms"("id") on delete cascade on update no action, foreign key("customer_id") references "customers"("id") on delete cascade on update no action);
CREATE TABLE IF NOT EXISTS "packages" ("id" integer primary key autoincrement not null, "package_slip" varchar not null, "date" date not null, "internal_notes" text, "team_id" integer not null, "created_at" datetime, "updated_at" datetime, "items" text not null, "shipped" tinyint(1) not null default '0', "sales_order_number" integer, foreign key("team_id") references "teams"("id") on delete cascade on update no action);
CREATE TABLE IF NOT EXISTS "sales_orders" ("id" integer primary key autoincrement not null, "customer_id" integer not null, "sales_order_number" varchar not null, "reference_number" varchar, "sales_order_date" date not null, "items" text not null, "total" double not null, "sub_total" double not null, "adjustment" double not null default '0', "shipment_charges" double not null default '0', "discount" double not null default '0', "expected_shippment_date" date, "payment_term_id" integer, "delivery_method_id" integer, "sales_person_id" integer, "customer_notes" varchar, "terms_and_conditions" varchar, "status" tinyint(1), "team_id" integer not null, "created_at" datetime, "updated_at" datetime, "invoiced" tinyint(1) not null default '0', "packaged" tinyint(1) not null default '0', "payed" tinyint(1) not null default '0', "shipped" tinyint(1) not null default '0', "email_sent" tinyint(1) not null default '0', "returned" tinyint(1) not null default '0', "delivered" tinyint(1) not null default '0', foreign key("payment_term_id") references "payment_terms"("id") on delete cascade on update no action, foreign key("delivery_method_id") references "delivery_methods"("id") on delete cascade on update no action, foreign key("sales_person_id") references "sales_persons"("id") on delete cascade on update no action, foreign key("team_id") references "teams"("id") on delete cascade on update no action);
CREATE TABLE IF NOT EXISTS "sales_returns" ("id" integer primary key autoincrement not null, "sales_returns_number" varchar not null, "date" date not null, "reason" varchar, "credit_only_goods" tinyint(1), "items" text not null, "created_at" datetime, "updated_at" datetime, "approved" tinyint(1) not null default '1', "received_date" date, "notes" varchar, "team_id" integer not null, "sales_order_number" varchar not null);
CREATE TABLE IF NOT EXISTS "inventory_adjustments" ("id" integer primary key autoincrement not null, "mode_of_adjustment" varchar not null, "reference_number" varchar not null, "date" date not null, "account" varchar not null, "reason" varchar, "description" varchar, "items" text not null, "created_at" datetime, "updated_at" datetime, "team_id" integer not null);
CREATE TABLE IF NOT EXISTS "purchase_orders" ("id" integer primary key autoincrement not null, "vendor_id" integer not null, "delivery_street" varchar not null, "delivery_city" varchar not null, "delivery_province" varchar not null, "delivery_country" varchar not null, "delivery_phone" varchar not null, "purchase_order_number" varchar not null, "reference_number" varchar not null, "purchase_order_date" date not null, "expected_delivery_date" date, "payment_terms" varchar not null, "shipment_preference" varchar not null, "customer_notes" varchar, "terms_and_conditions" varchar, "discount" double not null, "sub_total" double not null, "adjustment" double not null, "order_status" varchar not null default 'OPEN', "received" tinyint(1) not null default '0', "billed" tinyint(1) not null default '0', "total" double not null, "items" text not null, "team_id" integer not null, "created_at" datetime, "updated_at" datetime, "shipment_charges" double not null default '0', foreign key("team_id") references "teams"("id") on delete cascade on update no action, foreign key("vendor_id") references "vendors"("id") on delete cascade on update no action);
CREATE TABLE IF NOT EXISTS "team_admin" ("id" integer primary key autoincrement not null, "team_id" integer not null, "user_id" integer not null, "created_at" datetime, "updated_at" datetime, foreign key("team_id") references "teams"("id") on delete cascade, foreign key("user_id") references "users"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "customers" ("id" integer primary key autoincrement not null, "customer_type" varchar not null, "salutation" varchar not null, "first_name" varchar not null, "last_name" varchar not null, "company_name" varchar not null, "company_display_name" varchar not null, "email" varchar not null, "phone" varchar not null, "payment_terms" varchar not null, "billing_country" varchar not null, "billing_province" varchar not null, "billing_city" varchar not null, "billing_phone" varchar not null, "billing_street_1" varchar not null, "billing_street_2" varchar, "shipping_country" varchar not null, "shipping_province" varchar not null, "shipping_city" varchar not null, "shipping_phone" varchar not null, "shipping_street_1" varchar not null, "shipping_street_2" varchar not null, "remarks" varchar, "team_id" integer not null, "created_at" datetime, "updated_at" datetime, "tpin" varchar, foreign key("team_id") references "teams"("id") on delete cascade on update no action);
CREATE TABLE IF NOT EXISTS "shipments" ("id" integer primary key autoincrement not null, "shipment_order_number" varchar not null, "shipment_date" date not null, "delivery_method_id" integer not null, "tracking_number" varchar, "tracking_url" varchar, "shipping_charges" double not null default '0', "notes" varchar, "delivered" tinyint(1) not null default '0', "team_id" integer not null, "created_at" datetime, "updated_at" datetime, "packages" text not null, "customer_id" integer not null, "status" varchar not null default 'In Transit', foreign key("delivery_method_id") references "delivery_methods"("id") on delete cascade on update no action, foreign key("team_id") references "teams"("id") on delete cascade on update no action);
CREATE TABLE IF NOT EXISTS "payments_receiveds" ("id" integer primary key autoincrement not null, "payment_number" varchar not null, "payment_date" date not null, "amount_received" double not null, "bank_charges" double not null default '0', "payment_mode" varchar not null, "paid_through" varchar not null, "reference_number" varchar not null, "notes" varchar, "items" text not null, "customer_id" integer not null, "team_id" integer not null, "created_at" datetime, "updated_at" datetime, foreign key("team_id") references "teams"("id") on delete cascade on update no action, foreign key("customer_id") references "customers"("id") on delete cascade on update no action);
CREATE TABLE IF NOT EXISTS "transfer_orders" ("id" integer primary key autoincrement not null, "transfer_order_number" varchar not null, "date" date not null, "reason" varchar, "items" text not null, "delivered" tinyint(1) not null default '0', "source_warehouse_id" integer, "destination_warehouse_id" integer, "created_at" datetime, "updated_at" datetime, "team_id" integer not null, "costs" text, foreign key("source_warehouse_id") references "warehouses"("id") on delete cascade, foreign key("destination_warehouse_id") references "warehouses"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "warehouses" ("id" integer primary key autoincrement not null, "name" varchar not null, "attention" varchar, "street_1" varchar, "street_2" varchar, "city" varchar, "province" varchar, "country" varchar, "phone" varchar, "email" varchar, "is_active" tinyint(1), "created_at" datetime, "updated_at" datetime, "is_primary" tinyint(1) not null default '0', "team_id" integer not null);
CREATE TABLE IF NOT EXISTS "warehouse_items" ("id" integer primary key autoincrement not null, "warehouse_id" integer not null, "item_id" integer not null, "quantity" integer not null default '0', "created_at" datetime, "updated_at" datetime, "price_adjustment" double not null default '0', "cost_adjustment" double not null default '0', foreign key("item_id") references "item"("id") on delete cascade on update no action, foreign key("warehouse_id") references "warehouses"("id") on delete cascade on update no action);
CREATE TABLE IF NOT EXISTS "purchase_order_shipments" ("id" integer primary key autoincrement not null, "vendor_id" integer not null default '1', "purchase_order_id" integer not null default '1', "shipment_order_number" varchar not null, "shipment_date" date not null, "delivery_method_id" integer not null, "tracking_number" varchar, "tracking_url" varchar, "shipping_charges" double not null default '0', "notes" varchar, "delivered" tinyint(1) not null default '0', "team_id" integer not null default '1', "created_at" datetime, "updated_at" datetime, "status" varchar not null default 'In-Transit', "received" tinyint(1) not null default 'false', foreign key("vendor_id") references "vendors"("id") on delete cascade, foreign key("purchase_order_id") references "purchase_orders"("id") on delete cascade, foreign key("team_id") references "teams"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "purchase_receives" ("id" integer primary key autoincrement not null, "vendor_id" integer not null, "purchase_order_number" varchar not null, "purchase_receive_number" varchar not null, "received_date" date not null, "notes" varchar, "items" text not null, "team_id" integer not null, "created_at" datetime, "updated_at" datetime, "status" varchar not null default 'null', "received" tinyint(1) not null default '0', foreign key("team_id") references "teams"("id") on delete cascade on update no action, foreign key("vendor_id") references "vendors"("id") on delete cascade on update no action);
CREATE TABLE IF NOT EXISTS "quotations" ("id" integer primary key autoincrement not null, "customer_id" integer not null, "quotation_number" varchar not null, "reference_number" varchar, "quotation_date" date not null, "items" text not null, "total" double not null, "sub_total" double not null, "adjustment" double not null, "shipment_charges" double not null, "discount" double not null, "expected_shippment_date" date, "payment_term_id" integer, "delivery_method_id" integer, "sales_person_id" integer, "customer_notes" varchar, "terms_and_conditions" text, "status" varchar not null, "team_id" integer not null, "created_at" datetime, "updated_at" datetime, "report_number" varchar, "inco_term" varchar, "stock_in" varchar, "lead_time" varchar, "payment_time" varchar, foreign key("team_id") references "teams"("id") on delete cascade on update no action, foreign key("sales_person_id") references "sales_persons"("id") on delete cascade on update no action, foreign key("delivery_method_id") references "delivery_methods"("id") on delete cascade on update no action, foreign key("payment_term_id") references "payment_terms"("id") on delete cascade on update no action);
CREATE TABLE IF NOT EXISTS "pulse_values" ("id" integer primary key autoincrement not null, "timestamp" integer not null, "type" varchar not null, "key" text not null, "key_hash" varchar not null, "value" text not null);
CREATE TABLE IF NOT EXISTS "pulse_entries" ("id" integer primary key autoincrement not null, "timestamp" integer not null, "type" varchar not null, "key" text not null, "key_hash" varchar not null, "value" integer);
CREATE TABLE IF NOT EXISTS "pulse_aggregates" ("id" integer primary key autoincrement not null, "bucket" integer not null, "period" integer not null, "type" varchar not null, "key" text not null, "key_hash" varchar not null, "aggregate" varchar not null, "value" numeric not null, "count" integer);
CREATE TABLE IF NOT EXISTS "templates" ("id" integer primary key autoincrement not null, "tenant_id" integer not null, "template" text not null, "template_name" text not null, "created_at" datetime, "updated_at" datetime, foreign key("tenant_id") references "teams"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "global_templates" ("id" integer primary key autoincrement not null, "name" varchar not null, "template" varchar not null, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "notifications" ("id" varchar not null, "type" varchar not null, "notifiable_type" varchar not null, "notifiable_id" integer not null, "data" text not null, "read_at" datetime, "created_at" datetime, "updated_at" datetime, "tenant_id" integer not null, primary key ("id"));
